import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./login.css"
import Mainweatherpage from "./mainweatherpage";
import { UseStore } from "./store";
function Login() {
    const navigate = useNavigate()
    let [nameinput, changenameinput] = useState("")
    let [passwordinput, changepasswordinput] = useState("")
    let changebool = UseStore((state) => state.changebool)
    let changefullweather = UseStore((state) => state.changefullweather)
    function getinputn(e) {
        changenameinput(e.target.value)
    }
    function getinputp(e) {
        changepasswordinput(e.target.value)
    }
    async function func1() {  
        await fetch("http://localhost:5000/login", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
            body: JSON.stringify({nameforlog: nameinput, passwordforlog: passwordinput})
        }
        )
        let res2 = await fetch("http://localhost:5000/apisession", {
            method: "GET",
            credentials: "include"
        })  
        let usercreds = await res2.json()
        console.log(usercreds) //always gives logged in true and newuserid31, need to figure out why it lets users use the application if they havent logged in
        if(usercreds.loggedIn == true) {
            navigate("/weather")
        }
        
        let weatherdata  = await fetch("https://api.openweathermap.org/data/2.5/weather?q=London&appid=d782528f491fa0b8359a25fc07739daa&units=metric")
        let updatedweather = await weatherdata.json()
        let alldata = {maindata: updatedweather.main, city: updatedweather.name, weathertype: updatedweather.weather[0]}
        let alldataweather = await fetch("http://localhost:5000/weatherrender", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
            body: JSON.stringify({citysessionback: alldata})
        })
        let updatedalldata = await alldataweather.json()
        changefullweather(updatedalldata)
        changebool(true)
    }
    return<>
<div className="login-card">
  <h1>Log into an account</h1>

  <label>Username</label>
  <input value={nameinput} onChange={(e) => getinputn(e)} />

  <label>Password</label>
  <input value={passwordinput} onChange={(e) => getinputp(e)} type="password" />

  <button onClick={() => func1()}>Login</button>
</div>
    </>
}
export default Login
